from fastapi import FastAPI
import urllib.request, json
app = FastAPI(title='Hermes Gateway', version='1.0.0')
@app.get('/health')
def health():
    return {'status': 'ok', 'service': 'hermes-gateway'}
@app.post('/context')
def context_proxy(query: str, budget_tokens: int = 1500):
    req = urllib.request.Request('http://localhost:8643/v1/rag', data=json.dumps({'query': query}).encode(), headers={'Content-Type': 'application/json'})
    with urllib.request.urlopen(req, timeout=30) as resp:
        return json.loads(resp.read().decode())
